export const getThemeColorCodeFromOklch = ({
  c: e,
  h: m
}) => {
  if (e <= .05) return "grey";
  for (const {
    name: n,
    min: a,
    max: r
  } of o) if (m > a && m <= r) return n;
  return "grey";
};